// Selector inteligente de productos basado en conversiones
const products = $input.all()[0]?.json?.search_results || [];
const affiliateTag = $('Set Country-Specific Variables').first().json.affiliateTag;
const amazonDomain = $('Set Country-Specific Variables').first().json.amazonDomain;

const scoredProducts = products.map(product => {
  let score = 0;
  if (product.rating) score += (product.rating / 5) * 40;
  if (product.ratings_total) score += Math.min(product.ratings_total / 1000, 1) * 30;
  if (product.price?.value) {
    const price = product.price.value;
    if (price >= 20 && price <= 200) score += 20;
    else if (price > 200 && price <= 500) score += 15;
    else score += 5;
  }
  if (product.is_prime) score += 5;
  if (product.is_amazon_choice) score += 5;
  return {
    ...product,
    conversionScore: score,
    affiliateUrl: `https://${amazonDomain}/dp/${product.asin}?tag=${affiliateTag}`
  };
});

const topProducts = scoredProducts.sort((a, b) => b.conversionScore - a.conversionScore).slice(0, 5);
return topProducts.map(product => ({ json: product }));

