// Publicador multi-plataforma inteligente
const platforms = {
  facebook: {endpoint: 'https://graph.facebook.com/v18.0/me/feed', token: $env.FACEBOOK_PAGE_TOKEN, format: 'long_form'},
  instagram: {endpoint: 'https://graph.facebook.com/v18.0/me/media', token: $env.INSTAGRAM_TOKEN, format: 'visual_focused'},
  twitter: {endpoint: 'https://api.twitter.com/2/tweets', token: $env.TWITTER_BEARER_TOKEN, format: 'thread'},
  linkedin: {endpoint: 'https://api.linkedin.com/v2/shares', token: $env.LINKEDIN_TOKEN, format: 'professional'},
  tiktok: {endpoint: 'https://open-api.tiktok.com/share/video/upload', token: $env.TIKTOK_TOKEN, format: 'short_video'},
  pinterest: {endpoint: 'https://api.pinterest.com/v5/pins', token: $env.PINTEREST_TOKEN, format: 'visual_story'},
  youtube: {endpoint: 'https://www.googleapis.com/youtube/v3/videos', token: $env.YOUTUBE_TOKEN, format: 'long_video'},
  reddit: {endpoint: 'https://oauth.reddit.com/api/submit', token: $env.REDDIT_TOKEN, format: 'discussion'},
  telegram: {endpoint: `https://api.telegram.org/bot${$env.TELEGRAM_BOT_TOKEN}/sendMessage`, format: 'instant_message'},
  whatsapp: {endpoint: `https://graph.facebook.com/v18.0/${$env.WHATSAPP_PHONE_ID}/messages`, token: $env.WHATSAPP_TOKEN, format: 'personal_message'}
};

const content = $('Hypnotic Content Generator').first().json.choices[0].message.content;
const productData = $('Smart Product Selector').first().json;

const adaptedContent = Object.keys(platforms).map(platform => {
  let adaptedText = content;
  switch(platform) {
    case 'twitter':
      adaptedText = content.substring(0, 250) + '... 🧵👇';
      break;
    case 'instagram':
      adaptedText = content + '\n\n#affiliate #amazon #deals #shopping';
      break;
    case 'linkedin':
      adaptedText = 'Professional insight: ' + content;
      break;
    case 'tiktok':
      adaptedText = 'Watch this! ' + content.substring(0, 150);
      break;
  }
  return {
    platform,
    content: adaptedText,
    productUrl: productData.affiliateUrl,
    config: platforms[platform]
  };
});

return adaptedContent.map(item => ({ json: item }));

