// Optimizador de performance basado en IA
const analytics = $input.all();
const conversions = analytics.filter(item => item.json.status === 'converted');
const totalLeads = analytics.length;
const conversionRate = totalLeads === 0 ? 0 : (conversions.length / totalLeads) * 100;

const topCountries = {}, topInterests = {}, topPsychProfiles = {};
conversions.forEach(conversion => {
  const {country, interest, psychProfile} = conversion.json;
  topCountries[country] = (topCountries[country] || 0) + 1;
  topInterests[interest] = (topInterests[interest] || 0) + 1;
  topPsychProfiles[psychProfile] = (topPsychProfiles[psychProfile] || 0) + 1;
});
const recommendations = {
  bestCountries: Object.keys(topCountries).sort((a,b) => topCountries[b] - topCountries[a]).slice(0,3),
  bestInterests: Object.keys(topInterests).sort((a,b) => topInterests[b] - topInterests[a]).slice(0,3),
  bestPsychProfiles: Object.keys(topPsychProfiles).sort((a,b) => topPsychProfiles[b] - topPsychProfiles[a]).slice(0,3),
  conversionRate,
  totalRevenue: conversions.reduce((sum, c) => sum + (Number(c.json.conversionValue) || 0), 0),
  avgOrderValue: conversions.length ? conversions.reduce((sum, c) => sum + (Number(c.json.conversionValue) || 0), 0) / conversions.length : 0,
  optimization: conversionRate < 5 ? 'CRITICAL - Revisar copy y targeting' : conversionRate < 15 ? 'MODERATE - Optimizar headlines' : 'EXCELLENT - Escalar campaña'
};
return [{ json: recommendations }];
